"""Embed the baked ANNY rig into a SoA C header (soma_rig.h) so a native runtime
can skin the mesh with no Python and no runtime file load.  Reads soma_rig.npz
(rig + LBS weights + invbind + faces + rest), written by solve/adapters/bake/extract_rig.py
straight from PyTorch — no ONNX.  Run in the export env (numpy only):

    pixi run -e export python solve/adapters/bake/extract_rig.py && pixi run -e export python solve/adapters/bake/make_rig.py

Weights are stored sparsely with K = the actual max influences per vertex
(lossless: every non-zero weight is kept, shorter vertices padded with weight 0).
SoA arrays in soma_rig.h:
    soma_bind[V*3]        rest vertices
    soma_widx[V*K]        influencing joint indices (pad = 0, weight 0)
    soma_wval[V*K]        influence weights (pad = 0)
    soma_invbind[J*16]    inverse-bind, 4x4 row-major
    soma_restWorld[J*16]  rest world transform, 4x4 row-major
    soma_faces[F*3]       triangle vertex indices
"""
import numpy as np

NPZ, OUT = "soma_rig.npz", "solve/core/soma_rig.h"


def emit(f, ctype, name, arr, fmt):
    flat = arr.reshape(-1)
    f.write(f"static const {ctype} {name}[{flat.size}] = {{\n")
    for i in range(0, flat.size, 16):
        f.write("  " + ",".join(fmt % x for x in flat[i:i + 16]) + ",\n")
    f.write("};\n\n")


def main():
    d = np.load(NPZ, allow_pickle=True)
    bind = d["rest_verts"].astype(np.float32)      # (V,3)
    weights = d["skin_weights"].astype(np.float32)  # (V,J)
    invbind = d["invbind"].astype(np.float32)       # (J,4,4)
    V, J = weights.shape

    nz = np.count_nonzero(weights, axis=1)
    K = int(nz.max())  # lossless: hold every vertex's influences
    print(f"V={V} J={J}  influences/vertex: max(K)={K} mean={nz.mean():.2f}")
    widx = np.zeros((V, K), np.int32)
    wval = np.zeros((V, K), np.float32)
    for v in range(V):
        idx = np.nonzero(weights[v])[0]
        widx[v, :idx.size] = idx
        wval[v, :idx.size] = weights[v, idx]
    assert np.allclose(wval.sum(1), weights.sum(1))  # nothing dropped

    rig = np.load(NPZ, allow_pickle=True)
    faces = rig["faces"].astype(np.int32).reshape(-1, 3)
    F = faces.shape[0]
    rest = np.tile(np.eye(4, dtype=np.float32), (J, 1, 1))
    rest[:, :3, :3] = rig["rest_R"].astype(np.float32)
    rest[:, :3, 3] = rig["rest_pos"].astype(np.float32)

    with open(OUT, "w") as f:
        f.write("// AUTO-GENERATED by solve/adapters/bake/make_rig.py — the baked ANNY rig as SoA C arrays.\n")
        f.write("// Regenerate: pixi run -e export python solve/adapters/bake/make_rig.py\n#pragma once\n\n")
        f.write(f"#define SOMA_V {V}\n#define SOMA_J {J}\n#define SOMA_F {F}\n#define SOMA_K {K}\n\n")
        emit(f, "float", "soma_bind", bind, "%.9g")
        emit(f, "int", "soma_widx", widx, "%d")
        emit(f, "float", "soma_wval", wval, "%.9g")
        emit(f, "float", "soma_invbind", invbind, "%.9g")
        emit(f, "float", "soma_restWorld", rest, "%.9g")
        emit(f, "int", "soma_parents", rig["parents"].astype(np.int32), "%d")
        emit(f, "int", "soma_faces", faces, "%d")
        names = [str(n) for n in rig["joint_names"]]
        f.write(f"static const char *const soma_jointNames[SOMA_J] = {{\n")
        for n in names:
            f.write(f'  "{n}",\n')
        f.write("};\n\n")
        assert len(names) == J, (len(names), J)

    import os
    print(f"wrote {OUT} ({os.path.getsize(OUT) / 1e6:.2f} MB)")


if __name__ == "__main__":
    main()
